class Solution(object):
    def maximumAmount(self, coins):
        m, n = len(coins), len(coins[0])
        INF = float('-inf')
        # dp[i][j][k] = max coins at (i,j) having neutralized k robbers (k=0,1,2)
        dp = [[[INF]*3 for _ in range(n)] for _ in range(m)]
        dp[0][0][0] = coins[0][0]
        if coins[0][0] < 0:
            dp[0][0][1] = 0  # neutralize (0,0)

        for i in range(m):
            for j in range(n):
                for k in range(3):
                    if dp[i][j][k] == INF:
                        continue
                    val = coins[i][j] if (i > 0 or j > 0) else 0  # already counted
                    # Move right
                    if j + 1 < n:
                        nv = coins[i][j+1]
                        for nk in range(k, 3):
                            gain = 0 if (nk > k) else nv  # neutralize if nk > k
                            if nk == k:
                                gain = nv
                                new_val = dp[i][j][k] + nv
                            else:
                                # Use one neutralization on (i, j+1)
                                if nv < 0 and nk == k + 1:
                                    new_val = dp[i][j][k] + 0
                                else:
                                    continue
                            if new_val > dp[i][j+1][nk]:
                                dp[i][j+1][nk] = new_val
                    # Move down
                    if i + 1 < m:
                        nv = coins[i+1][j]
                        for nk in range(k, 3):
                            if nk == k:
                                new_val = dp[i][j][k] + nv
                            elif nk == k + 1 and nv < 0:
                                new_val = dp[i][j][k] + 0
                            else:
                                continue
                            if new_val > dp[i+1][j][nk]:
                                dp[i+1][j][nk] = new_val

        return max(dp[m-1][n-1])
